import 'dart:io';
import 'package:flutter/material.dart';
import 'package:image_picker/image_picker.dart';
import '../../owner/owner_store.dart';
import '../../widgets/owner_layout.dart';

class OwnerProfileScreen extends StatefulWidget { const OwnerProfileScreen({super.key}); @override State<OwnerProfileScreen> createState()=>_State(); }
class _State extends State<OwnerProfileScreen>{final store=OwnerStore.instance;late final phone=TextEditingController(text:store.profile.phone),address=TextEditingController(text:store.profile.address),about=TextEditingController(text:store.profile.about);String? imagePath;@override void dispose(){phone.dispose();address.dispose();about.dispose();super.dispose();}Future<void> pick()async{final image=await ImagePicker().pickImage(source:ImageSource.gallery,imageQuality:80);if(image!=null)setState(()=>imagePath=image.path);}void save(){if(phone.text.trim().length<7||address.text.trim().isEmpty){ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Enter a valid phone number and address.')));return;}store.updateProfile(phone:phone.text.trim(),address:address.text.trim(),about:about.text.trim(),imagePath:imagePath);ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Profile updated successfully.')));}@override Widget build(BuildContext context){final p=store.profile;final selected=imagePath??p.imagePath;return OwnerLayout(child:SingleChildScrollView(padding:const EdgeInsets.all(24),child:Column(crossAxisAlignment:CrossAxisAlignment.start,children:[Row(children:[GestureDetector(onTap:pick,child:CircleAvatar(radius:36,backgroundImage:selected!=null?FileImage(File(selected)):const AssetImage('assets/images/profile_kamal.jpg') as ImageProvider,child:const Align(alignment:Alignment.bottomRight,child:CircleAvatar(radius:11,child:Icon(Icons.camera_alt,size:13))))),const SizedBox(width:16),Text(p.fullName,style:const TextStyle(fontSize:22,fontWeight:FontWeight.bold,color:Colors.black))]),const SizedBox(height:32),label('NIC No.'),field(TextEditingController(text:p.nic),readOnly:true),label('Your Email'),field(TextEditingController(text:p.email),readOnly:true,icon:Icons.mail_outline),label('Phone Number'),field(phone,icon:Icons.phone_outlined),label('Address'),field(address),label('About'),field(about,maxLines:3),const SizedBox(height:48),SizedBox(width:double.infinity,height:56,child:ElevatedButton(style:ElevatedButton.styleFrom(backgroundColor:const Color(0xFF0F172A),foregroundColor:Colors.white,shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(8))),onPressed:save,child:const Text('Update',style:TextStyle(fontSize:16))))])));}Widget label(String t)=>Padding(padding:const EdgeInsets.only(bottom:8,top:16),child:Text(t,style:const TextStyle(fontWeight:FontWeight.bold,color:Colors.black87)));Widget field(TextEditingController c,{IconData? icon,int maxLines=1,bool readOnly=false})=>TextField(controller:c,maxLines:maxLines,readOnly:readOnly,decoration:InputDecoration(prefixIcon:icon==null?null:Icon(icon),filled:readOnly,fillColor:readOnly?Colors.grey.shade100:null,contentPadding:const EdgeInsets.symmetric(horizontal:16,vertical:16),enabledBorder:OutlineInputBorder(borderRadius:BorderRadius.circular(12),borderSide:BorderSide(color:Colors.grey.shade200)),focusedBorder:OutlineInputBorder(borderRadius:BorderRadius.circular(12),borderSide:const BorderSide(color:Color(0xFF152238)))));}
